//! Auto-generated by the spec-word-compliance workflow for the area
//! "Paragraph-mark run properties (pPr/rPr, pilcrow formatting, mark del/ins)".
//!
//! Each `#[test]` encodes a Word-consumption / serializer-conformance rule mined
//! from ECMA-376 / ISO 29500-1 / MS-OI29500 / MS-OE376. A **FAILING** assertion
//! here means stemma diverges from real-Word behaviour — i.e. it documents a real
//! Word-compliance gap, NOT something to be "made green" by weakening the test.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an UNEDITED document reflects stemma's
//! verbatim-preservation contract, not Word's render-time normalization.
//! Therefore xmlContains/xmlOmits assertions here are used ONLY for markup the
//! serializer actively generates/omits as a structural choice (e.g. NOT
//! synthesizing an absent mark rPr). Consumption rules ("X does not change the
//! run text") are asserted on the READ side via read_accepted()/read_rejected().

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::{Document, validate};
use zip::write::FileOptions;

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a minimal valid `.docx` whose `word/body` is `body_xml`. `extra_parts`
/// is a list of `(part_name, xml)` (e.g. `word/styles.xml`, `word/numbering.xml`)
/// that get zipped in AND registered as Content-Types overrides + document rels.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-Types: base defaults + the document override, plus an override for
    // each extra part keyed off its filename.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    let mut doc_rels = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">"#,
    );
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        // part is e.g. "word/styles.xml" / "word/numbering.xml"
        let part_abs = format!("/{part}");
        let (content_type, rel_type, target) = match *part {
            "word/styles.xml" => (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            ),
            "word/numbering.xml" => (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            ),
            other => panic!("unhandled extra part content-type for {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_abs}" ContentType="{content_type}"/>"#
        ));
        doc_rels.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    doc_rels.push_str("</Relationships>");

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse → serialize(default) → return the emitted `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{ctx} — expected document to open clean (no validation errors), got ok={} issues={:?}",
        report.ok,
        report.issues
    );
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[test]
fn list_item_mark_formatting_leaves_run_text() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr><w:rPr><w:b/></w:rPr></w:pPr><w:r><w:t>Item text</w:t></w:r></w:p><w:sectPr/>"#;
    let extra = [(
        "word/numbering.xml",
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#,
    )];
    let b = make_docx(body, &extra);

    assert_eq!(
        accept_text(&b).trim(),
        "Item text",
        "MS-OI29500 §2.1.57 / ISO 29500-1 §17.3.1.29: applying run formatting (bold) to a list \
         item's paragraph mark does not change the run text; the accepted read must be exactly \
         'Item text'."
    );
    assert_opens_clean(
        &b,
        "list_item_mark_formatting_leaves_run_text (MS-OI29500 §2.1.57; §17.3.1.29): a numbered \
         paragraph with a bold paragraph-mark rPr is valid CT_ParaRPr — Word opens without repair",
    );
}

#[test]
fn deleted_mark_with_mark_bold_merges_keeping_both_run_texts() {
    let body = r#"<w:p><w:pPr><w:rPr><w:b/><w:del w:id="5" w:author="a"/></w:rPr></w:pPr><w:r><w:t>Hello </w:t></w:r></w:p><w:p><w:r><w:t>World</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "Hello World",
        "ECMA-376 §17.13.5.15: accepting the deleted mark merges this paragraph with the \
         following one and both run contents survive ('those contents shall not automatically be \
         marked as deleted'); the mark's bold (§17.3.1.29 / MS-OI29500 §2.1.57) does not alter run \
         text — accepted text must be 'Hello World'."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "Hello \n\nWorld".trim(),
        "ECMA-376 §17.13.5.15 / §17.3.1.29: rejecting the deleted mark restores the mark; the two \
         paragraphs remain separate with both run texts intact regardless of mark bold — rejected \
         text must be 'Hello \\n\\nWorld'."
    );
    assert_opens_clean(
        &b,
        "deleted_mark_with_mark_bold_merges_keeping_both_run_texts (§17.3.1.29 CT_ParaRPr): a \
         mark rPr carrying both EG_RPrBase formatting (b) and an EG_ParaRPrTrackChanges del is \
         valid — Word opens without repair",
    );
}

#[test]
fn rprchange_snapshot_del_ignored_keeps_two_paragraphs() {
    let body = r#"<w:p><w:pPr><w:rPr><w:b/><w:rPrChange w:id="1" w:author="A" w:date="2024-01-01T00:00:00Z"><w:rPr><w:del w:id="2" w:author="A" w:date="2024-01-01T00:00:00Z"/><w:i/></w:rPr></w:rPrChange></w:rPr></w:pPr><w:r><w:t>one</w:t></w:r></w:p><w:p><w:r><w:t>two</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "one\n\ntwo".trim(),
        "MS-OI29500 §2.1.58 / ISO 29500-1 §17.3.1.30: Word ignores ins/del/moveFrom/moveTo/oMath \
         in the previous-mark rPr (rPrChange snapshot) and uses the current mark, which has no del; \
         the accepted view must keep two separate paragraphs ('one\\n\\ntwo')."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "one\n\ntwo".trim(),
        "MS-OI29500 §2.1.58 / §17.13.5.15: rejecting cannot revive a deletion that was never live \
         (the del lives only in the historical rPrChange snapshot Word ignores); rejected view \
         must equal the accepted view ('one\\n\\ntwo')."
    );
    assert_opens_clean(
        &b,
        "rprchange_snapshot_del_ignored_keeps_two_paragraphs (§17.3.1.30 CT_ParaRPrOriginal): an \
         rPrChange whose inner rPr carries a del child is schema-valid — Word opens without repair",
    );
}

#[test]
fn rprchange_snapshot_ins_ignored_and_preserved_verbatim() {
    let body = r#"<w:p><w:pPr><w:rPr><w:b/><w:rPrChange w:id="1" w:author="A" w:date="2024-01-01T00:00:00Z"><w:rPr><w:ins w:id="2" w:author="A" w:date="2024-01-01T00:00:00Z"/><w:i/></w:rPr></w:rPrChange></w:rPr></w:pPr><w:r><w:t>one</w:t></w:r></w:p><w:p><w:r><w:t>two</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "one\n\ntwo".trim(),
        "MS-OI29500 §2.1.58 / ISO 29500-1 §17.3.1.30: Word ignores the ins in the previous-mark \
         rPr snapshot; the current mark has no ins, so the accepted view keeps the two paragraphs \
         distinct ('one\\n\\ntwo')."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "one\n\ntwo".trim(),
        "MS-OI29500 §2.1.58: the snapshot ins is not a live insertion, so rejecting does not merge \
         the paragraphs; rejected view equals accepted view ('one\\n\\ntwo')."
    );
    assert_opens_clean(
        &b,
        "rprchange_snapshot_ins_ignored_and_preserved_verbatim (§17.3.1.30 CT_ParaRPrOriginal): an \
         rPrChange snapshot carrying an ins child is valid — Word opens without repair",
    );
}

#[test]
fn specvanish_without_vanish_on_mark_keeps_run_text_visible() {
    let body = r#"<w:p><w:pPr><w:rPr><w:specVanish/></w:rPr></w:pPr><w:r><w:t>hello</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "hello",
        "MS-OI29500 §2.1.97 / ISO 29500-1 §17.3.2.36 / §17.3.1.29: specVanish without vanish is \
         ignored by Word; it is a mark-glyph hide hint only, so the run text 'hello' stays visible \
         in the accepted read view."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "hello",
        "MS-OI29500 §2.1.97: specVanish is not a tracked change; rejecting changes nothing and the \
         run text remains 'hello'."
    );
    assert_opens_clean(
        &b,
        "specvanish_without_vanish_on_mark_keeps_run_text_visible (§17.3.2.36): specVanish is a \
         valid boolean property of CT_ParaRPr — Word opens without repair",
    );
}

#[test]
fn highlight_on_paragraph_mark_does_not_leak_into_run_text() {
    let body = r#"<w:p><w:pPr><w:rPr><w:highlight w:val="yellow"/></w:rPr></w:pPr><w:r><w:t>visible</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "visible",
        "MS-OI29500 §2.1.57 / ISO 29500-1 §17.3.2.15 / §17.3.1.29: a highlight on the \
         paragraph-mark rPr colors only the mark glyph; it does not propagate into the run text, \
         so the accepted read view is exactly 'visible'."
    );
    assert_opens_clean(
        &b,
        "highlight_on_paragraph_mark_does_not_leak_into_run_text (§17.3.2.15): highlight is a valid \
         child of the paragraph-mark rPr (CT_ParaRPr) — Word opens without repair",
    );
}

#[test]
fn mark_rprchange_empty_prior_snapshot_reject_clears_mark_formatting() {
    let body = r#"<w:p><w:pPr><w:rPr><w:b/><w:rPrChange w:id="3" w:author="a" w:date="2024-01-01T00:00:00Z"><w:rPr/></w:rPrChange></w:rPr></w:pPr><w:r><w:t>visible text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "mark_rprchange_empty_prior_snapshot_reject_clears_mark_formatting (§A.1 \
         CT_ParaRPrOriginal): an empty inner w:rPr is valid (both child groups minOccurs=0) — Word \
         opens without repair",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "visible text",
        "ISO 29500-1 §17.3.1.30 / MS-OI29500 §2.1.57: accepting a mark rPrChange keeps current \
         mark formatting and drops the record; mark-glyph formatting never alters run text, so \
         accepted text is just the run text 'visible text'."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "visible text",
        "ECMA-376 §17.13.5.30 / MS-OI29500 §2.1.57: rejecting restores the empty prior mark \
         snapshot (mark un-bolded); this is mark-glyph-only and does not change run content, so \
         rejected text equals the run text 'visible text'."
    );
}

#[test]
fn del_in_prior_mark_snapshot_is_ignored_no_paragraph_merge() {
    let body = r#"<w:p><w:pPr><w:rPr><w:rPrChange w:id="9" w:author="a" w:date="2024-01-01T00:00:00Z"><w:rPr><w:del w:id="10" w:author="a" w:date="2024-01-01T00:00:00Z"/></w:rPr></w:rPrChange></w:rPr></w:pPr><w:r><w:t>First</w:t></w:r></w:p><w:p><w:r><w:t>Second</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "del_in_prior_mark_snapshot_is_ignored_no_paragraph_merge (§17.3.1.30 \
         CT_ParaRPrOriginal): del inside the prior snapshot is schema-valid (EG_ParaRPrTrackChanges \
         minOccurs=0) — Word opens without repair",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "First\n\nSecond".trim(),
        "MS-OE376 §2.1.62 / ISO 29500-1 §17.3.1.30 / §17.13.5.15: Word ignores del in the \
         previous mark properties; the current mark has no del, so accept leaves the mark intact \
         and the two paragraphs stay separate ('First\\n\\nSecond')."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "First\n\nSecond".trim(),
        "MS-OE376 §2.1.62: the prior-snapshot del is ignored, so rejecting cannot merge; two \
         separate paragraphs remain ('First\\n\\nSecond')."
    );
}

#[test]
fn para_mark_bold_xor_with_bold_paragraph_style_preserves_mark_b_and_text() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="BoldPara"/><w:rPr><w:b/></w:rPr></w:pPr><w:r><w:t>mark xor text</w:t></w:r></w:p><w:sectPr/>"#;
    let extra = [(
        "word/styles.xml",
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr/></w:rPrDefault><w:pPrDefault><w:pPr/></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:styleId="BoldPara"><w:name w:val="Bold Para"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#,
    )];
    let b = make_docx(body, &extra);

    assert_opens_clean(
        &b,
        "para_mark_bold_xor_with_bold_paragraph_style_preserves_mark_b_and_text (§17.7.3, \
         §17.3.1.29): a mark w:b under a bold paragraph style is valid CT_ParaRPr — Word opens \
         without repair regardless of the XOR resolution",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "mark xor text",
        "ISO 29500-1 §17.7.3 / §17.3.1.29 / MS-OI29500 §2.1.57: toggle XOR is appearance-only and \
         never deletes or alters content; the accept view keeps the run text intact \
         ('mark xor text')."
    );
}

#[test]
fn para_mark_inherits_style_bold_without_synthesizing_explicit_mark_rpr() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="BoldPara"/></w:pPr><w:r><w:t>inherited mark bold</w:t></w:r></w:p><w:sectPr/>"#;
    let extra = [(
        "word/styles.xml",
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr/></w:rPrDefault><w:pPrDefault><w:pPr/></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:styleId="BoldPara"><w:name w:val="Bold Para"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#,
    )];
    let b = make_docx(body, &extra);
    let xml = reserialize(&b);

    assert_opens_clean(
        &b,
        "para_mark_inherits_style_bold_without_synthesizing_explicit_mark_rpr (§17.3.1.29): a \
         paragraph with only a pStyle reference and no mark rPr is valid — Word opens without \
         repair",
    );
    assert!(
        !xml.contains("<w:rPr><w:b/></w:rPr></w:pPr>"),
        "ISO 29500-1 §17.3.1.29 / §17.7.1 / MS-OI29500 §2.1.57: an absent mark rPr means \
         'inherit'; stemma must NOT synthesize an explicit mark rPr carrying the style's inherited \
         bold. Found '<w:rPr><w:b/></w:rPr></w:pPr>' in emitted XML: {xml}"
    );
    assert!(
        xml.contains(r#"<w:pStyle w:val="BoldPara"/>"#),
        "ISO 29500-1 §17.3.1.29: the style reference (the source of the inherited mark bold) must \
         be preserved verbatim. Missing '<w:pStyle w:val=\"BoldPara\"/>' in emitted XML: {xml}"
    );
}

