#[test]
fn delete_final_paragraph_mark_is_noop_merge() {
    let body = r#"<w:p><w:r><w:t>First</w:t></w:r></w:p><w:p><w:pPr><w:rPr><w:del w:id="9" w:author="a"/></w:rPr></w:pPr><w:r><w:t>Last</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "First\n\nLast".trim(),
        "ECMA-376 §17.13.5.15: a deleted mark merges with the FOLLOWING paragraph; the final mark \
         has no following paragraph, so accept is a no-op merge and both paragraphs' text survives \
         as separate paragraphs ('First\\n\\nLast')."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "First\n\nLast".trim(),
        "ECMA-376 §17.13.5.15 / §17.3.1.29: rejecting the deleted mark restores the mark; the two \
         paragraphs remain separate, text unchanged ('First\\n\\nLast')."
    );
    assert_opens_clean(
        &b,
        "delete_final_paragraph_mark_is_noop_merge (§17.3.1.29 CT_ParaRPr): w:del on the \
         paragraph-mark rPr (EG_ParaRPrTrackChanges) is valid — Word opens without repair",
    );
}
